package com.google.gson.protobuf.generated;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.protobuf.Descriptors.FileDescriptor;
import com.google.protobuf.ExtensionRegistry;
import com.google.protobuf.ExtensionRegistryLite;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import java.lang.reflect.Field;

class AnnotationsTest {

  @BeforeAll
  static void setUp() throws Exception {
    // Use reflection to set the private static descriptor field to a mock
    Field descriptorField = Annotations.class.getDeclaredField("descriptor");
    descriptorField.setAccessible(true);
    FileDescriptor mockDescriptor = mock(FileDescriptor.class);
    descriptorField.set(null, mockDescriptor);
  }

  @Test
  void testGetDescriptor_returnsDescriptor() {
    FileDescriptor descriptor = Annotations.getDescriptor();
    assertNotNull(descriptor);
  }

  @Test
  void testRegisterAllExtensions_withExtensionRegistryLite() {
    ExtensionRegistryLite registryLite = mock(ExtensionRegistryLite.class);
    // No exception expected
    Annotations.registerAllExtensions(registryLite);
  }

  @Test
  void testRegisterAllExtensions_withExtensionRegistry() {
    ExtensionRegistry registry = mock(ExtensionRegistry.class);
    // No exception expected
    Annotations.registerAllExtensions(registry);
  }

  @Test
  void testSerializedNameAndSerializedValueConstants() {
    // Verify the field numbers
    assertEquals(92066888, Annotations.SERIALIZED_NAME_FIELD_NUMBER);
    assertEquals(92066888, Annotations.SERIALIZED_VALUE_FIELD_NUMBER);

    // Verify that serializedName and serializedValue are not null
    assertNotNull(Annotations.serializedName);
    assertNotNull(Annotations.serializedValue);
  }

  @Test
  void testPrivateConstructor() throws Exception {
    var constructor = Annotations.class.getDeclaredConstructor();
    constructor.setAccessible(true);
    var instance = constructor.newInstance();
    assertNotNull(instance);
  }
}
